1	import { useState, useMemo, useEffect } from "react";
2	import { BrowserRouter, Routes, Route } from "react-router-dom";
3	import { CacheProvider } from "pipesy";
4	import Calendar from "./Calendar";
5	import Activity from "./Activity";
6	import LandingPage from "./LandingPage";
7	import AuthModal from "./AuthModal";
8	import SubscriptionDialog from "./SubscriptionDialog";
9	import OnboardingNotification from "./OnboardingNotification";
10	import PreviousWeekDialog from "./PreviousWeekDialog";
11	import CreateMomentumDialog from "./CreateMomentumDialog";
12	import Survey from "./components/Survey";
13	import TopBar from "./TopBar";
14	import MobileBlocker from "./MobileBlocker";
15	import Terms from "./Terms";
16	import { useAuthentication } from "./hooks/useAuthentication";
17	import { useTheme } from "./hooks/useTheme";
18	import { useFontSize } from "./hooks/useFontSize";
19	import { useOnboarding } from "./contexts/OnboardingContext";
20	import { OnboardingProvider } from "./contexts/OnboardingContext";
21	import { useMarkAppInstalled } from "./hooks/useMarkAppInstalled";
22	import { useTodosData } from "./hooks/useTodosData";
23	import { useTodoOperations } from "./hooks/useTodoOperations";
24	import { useEditProfile } from "./hooks/useEditProfile";
25	import { useActivity } from "./hooks/useActivity";
26	import { useSurvey } from "./hooks/useSurvey";
27	import { useFirestoreConnection } from "./hooks/useFirestoreConnection";
28	import DisconnectedNotification from "./DisconnectedNotification";
29	import { getOldUncompletedTodos, getNextWorkday } from "./utils/todos";
30	import {
31	  trackAppOpened,
32	  trackBulkTodoMove,
33	} from "./firebase/analytics";
34	import { isMobileDevice } from "./utils/device";
35	import { getSequentialWeek } from "./utils/activity";
36	import {
37	  collection,
38	  query,
39	  where,
40	  getDocs,
41	  doc,
42	  onSnapshot,
43	} from "firebase/firestore";
44	import { db } from "./firebase";
45	import { reflectionWeekConverter, type WeekNote } from "./firebase/types/reflection";
46	
47	export interface Todo {
48	  id: string;
49	  text: string;
50	  url?: string;
51	  completed: boolean;
52	  date: string; // ISO date string (YYYY-MM-DD)
53	  position: string;
54	  moveCount?: number;
55	  createdAt?: Date;
56	  updatedAt?: Date;
57	  completedAt?: Date;
58	  sessions?: Array<{ minutes: number; deepFocus: boolean; createdAt: Date }>;
59	}
60	
61	function AppContent() {
62	  const [authentication] = useAuthentication();
63	  const { todos: firebaseTodos, isLoading, connectionStatus } = useTodosData();
64	  const [showSubscriptionDialog, setShowSubscriptionDialog] = useState(false);
65	  const [authModalState, setAuthModalState] = useState(false);
66	  const [hasLeftLandingPage, setHasLeftLandingPage] = useState(() => {
67	    // Check if user has already left the landing page
68	    return localStorage.getItem("hasLeftLandingPage") === "true";
69	  });
70	  const [currentView, setCurrentView] = useState<"calendar" | "activity">(
71	    "calendar"
72	  );
73	  const [activityYear, setActivityYear] = useState(() =>
74	    new Date().getFullYear()
75	  );
76	  const [isLoadingActivity, setIsLoadingActivity] = useState(false);
77	  const [shouldPulsate, setShouldPulsate] = useState(false);
78	  const [pendingView, setPendingView] = useState<
79	    "calendar" | "activity" | null
80	  >(null);
81	  const [previousWeekDialog, setPreviousWeekDialog] = useState<{
82	    show: boolean;
83	    notes: WeekNote[];
84	    week: number;
85	    year: number;
86	    todoCount: number;
87	    dailyCounts: [number, number, number, number, number];
88	    userId: string;
89	    sessionsWithoutDistractions?: number;
90	    totalFocusTime?: number;
91	    averageFocusTime?: number;
92	  } | null>(null);
93	  const [createMomentumDialog, setCreateMomentumDialog] = useState<{
94	    show: boolean;
95	    todo: Todo | null;
96	  } | null>(null);
97	  const [focusState, setFocusState] = useState<{
98	    todo: Todo | null;
99	    isMinimized: boolean;
100	    onRestore: () => void;
101	  }>({ todo: null, isMinimized: false, onRestore: () => {} });
102	  const onboarding = useOnboarding();
103	  const profile = authentication.profile;
104	  const [, editProfile] = useEditProfile();
105	
106	  // Fetch activity data at App level so it persists across view changes
107	  const { activityWeeks, loading: activityLoading } = useActivity(activityYear);
108	
109	  // Survey hook for one-week check-in
110	  const { activeSurvey, dismissSurvey, submitSurvey } = useSurvey({
111	    profile: authentication.user ? authentication.profile : null,
112	    userId: authentication.user?.uid || null,
113	  });
114	
115	  // Track if we've seen an authenticated user in this session
116	  const [hadAuthenticatedUser, setHadAuthenticatedUser] = useState(false);
117	
118	  useEffect(() => {
119	    if (authentication.user) {
120	      setHadAuthenticatedUser(true);
121	
122	      // If user signed in while hasLeftLandingPage is false, set it to true
123	      // This handles the case where LandingPage unmounts before its useEffect runs
124	      if (!hasLeftLandingPage) {
125	        localStorage.setItem("hasLeftLandingPage", "true");
126	        setHasLeftLandingPage(true);
127	      }
128	    } else if (!authentication.isAuthenticating && hadAuthenticatedUser) {
129	      // User just signed out
130	      const hasLeftInStorage = localStorage.getItem("hasLeftLandingPage") === "true";
131	      if (!hasLeftInStorage) {
132	        setHasLeftLandingPage(false);
133	      }
134	    }
135	  }, [authentication.user, authentication.isAuthenticating, hasLeftLandingPage, hadAuthenticatedUser]);
136	
137	  // Auto-start tutorial for authenticated users who haven't completed onboarding
138	  useEffect(() => {
139	    if (
140	      authentication.user &&
141	      profile !== null &&
142	      profile.isOnboarded !== true &&
143	      !onboarding.isOnboarding
144	    ) {
145	      onboarding.startOnboarding();
146	    }
147	    // eslint-disable-next-line react-hooks/exhaustive-deps
148	  }, [authentication.user, profile]);
149	
150	
151	  // Sync state with localStorage when user signs out
152	  // (localStorage is cleared by the sign out button handler)
153	  useEffect(() => {
154	    if (
155	      !authentication.user &&
156	      !authentication.isAuthenticating &&
157	      hadAuthenticatedUser
158	    ) {
159	      // User signed out - check if localStorage was cleared
160	      const hasLeftLandingPageInStorage = localStorage.getItem("hasLeftLandingPage") === "true";
161	      if (hasLeftLandingPage && !hasLeftLandingPageInStorage) {
162	        setHasLeftLandingPage(false);
163	      }
164	    }
165	  }, [
166	    authentication.user,
167	    authentication.isAuthenticating,
168	    hadAuthenticatedUser,
169	    hasLeftLandingPage,
170	  ]);
171	
172	  // Todo operations
173	  const todoOperations = useTodoOperations({
174	    profile,
175	    onShowSubscriptionDialog: () => setShowSubscriptionDialog(true),
176	  });
177	
178	  // Merge pending todos with Firebase todos (filter out pending todos that are already confirmed)
179	  const todos = useMemo(() => {
180	    const pending = todoOperations.getPendingAsTodos();
181	    const firebaseIds = new Set(firebaseTodos.map(t => t.id));
182	    const uniquePending = pending.filter(p => !firebaseIds.has(p.id));
183	    return [...uniquePending, ...firebaseTodos];
184	  }, [firebaseTodos, todoOperations]);
185	
186	  // Clean up pending todos when they appear in Firebase
187	  useEffect(() => {
188	    const pendingTodos = todoOperations.getPendingAsTodos();
189	    const firebaseTodoIds = new Set(firebaseTodos.map((t) => t.id));
190	
191	    pendingTodos.forEach((pending) => {
192	      if (firebaseTodoIds.has(pending.id)) {
193	        todoOperations.removePending(pending.id);
194	      }
195	    });
196	  }, [firebaseTodos, todoOperations]);
197	
198	  // Debug: Check for duplicate positions
199	  useEffect(() => {
200	    const positionMap = new Map<string, string[]>();
201	    todos.forEach((todo) => {
202	      const date = todo.date;
203	      if (!positionMap.has(date)) {
204	        positionMap.set(date, []);
205	      }
206	      positionMap.get(date)!.push(todo.position);
207	    });
208	
209	    positionMap.forEach((positions, date) => {
210	      const duplicates = positions.filter(
211	        (pos, index) => positions.indexOf(pos) !== index
212	      );
213	      if (duplicates.length > 0) {
214	        console.error(
215	          `🔴 Duplicate positions found for date ${date}:`,
216	          duplicates
217	        );
218	        const todosForDate = todos.filter((t) => t.date === date);
219	        console.error(
220	          "All todos for this date:",
221	          todosForDate.map((t) => ({
222	            id: t.id,
223	            position: t.position,
224	            text: t.text,
225	          }))
226	        );
227	      }
228	    });
229	  }, [todos]);
230	
231	  // Initialize theme system
232	  useTheme();
233	
234	  // Initialize font size system
235	  useFontSize();
236	
237	  // Initialize Firestore connection management
238	  useFirestoreConnection();
239	
240	  // Mark app as installed when running in desktop app (only when authenticated)
241	  useMarkAppInstalled();
242	
243	  // Check if running in Electron
244	  const isElectron = window.navigator.userAgent.includes("Electron");
245	
246	  // Track app opened only once on mount
247	  useEffect(() => {
248	    trackAppOpened(isElectron);
249	    // eslint-disable-next-line react-hooks/exhaustive-deps
250	  }, []);
251	
252	  // Previous week dialog detection
253	  useEffect(() => {
254	    const checkPreviousWeekDialog = async () => {
255	      // Only run if user is authenticated and has a profile
256	      if (!authentication.user || !profile) return;
257	
258	      const now = new Date();
259	      const dayOfWeek = now.getDay();
260	
261	      // Don't show on weekends (0 = Sunday, 6 = Saturday)
262	      if (dayOfWeek === 0 || dayOfWeek === 6) return;
263	
264	      // Get current week info
265	      const { year, week } = getSequentialWeek(now);
266	      const currentWeekKey = `${year}-${week}`;
267	
268	      // Check if user has already seen the dialog for this week
269	      if (profile.lastPreviousWeekDialogWeek === currentWeekKey) return;
270	
271	      // Get previous week
272	      const previousWeek = week - 1;
273	      const previousYear = previousWeek < 1 ? year - 1 : year;
274	      const previousWeekNumber = previousWeek < 1 ? 52 : previousWeek;
275	
276	      try {
277	        // Query previous week's reflection
278	        const reflectionRef = collection(db, "reflections").withConverter(
279	          reflectionWeekConverter
280	        );
281	        const q = query(
282	          reflectionRef,
283	          where("userId", "==", authentication.user.uid),
284	          where("year", "==", previousYear),
285	          where("week", "==", previousWeekNumber)
286	        );
287	
288	        const querySnapshot = await getDocs(q);
289	
290	        if (!querySnapshot.empty) {
291	          const reflectionDoc = querySnapshot.docs[0].data();
292	
293	          // Only show if there are notes
294	          if (reflectionDoc.notes && reflectionDoc.notes.length > 0) {
295	            // Calculate daily counts (Mon-Fri)
296	            const dailyCounts: [number, number, number, number, number] = [
297	              0, 0, 0, 0, 0,
298	            ];
299	            reflectionDoc.completedTodos.forEach((todo) => {
300	              const todoDate = new Date(todo.date);
301	              const dayOfWeek = todoDate.getDay(); // 0=Sun, 1=Mon, ..., 5=Fri
302	              if (dayOfWeek >= 1 && dayOfWeek <= 5) {
303	                dailyCounts[dayOfWeek - 1]++; // Convert to 0-4 index
304	              }
305	            });
306	
307	            setPreviousWeekDialog({
308	              show: true,
309	              notes: reflectionDoc.notes,
310	              week: previousWeekNumber,
311	              year: previousYear,
312	              todoCount: reflectionDoc.completedTodos.length,
313	              dailyCounts,
314	              userId: authentication.user.uid,
315	              sessionsWithoutDistractions: reflectionDoc.sessionsWithoutDistractions,
316	              totalFocusTime: reflectionDoc.totalFocusTime,
317	              averageFocusTime: reflectionDoc.averageFocusTime,
318	            });
319	
320	            // Mark as seen for this week
321	            editProfile({ lastPreviousWeekDialogWeek: currentWeekKey });
322	          }
323	        }
324	      } catch (error) {
325	        console.error("Failed to fetch previous week reflection:", error);
326	      }
327	    };
328	
329	    checkPreviousWeekDialog();
330	  }, [authentication.user, profile]);
331	
332	  // Real-time sync: Close dialog if reflection is saved on another device
333	  useEffect(() => {
334	    if (!previousWeekDialog) return;
335	
336	    const reflectionDocId = `${previousWeekDialog.userId}_${previousWeekDialog.year}_${previousWeekDialog.week}`;
337	    const reflectionDocRef = doc(db, "reflections", reflectionDocId).withConverter(
338	      reflectionWeekConverter
339	    );
340	
341	    // Track the initial timestamp to detect changes
342	    let initialTimestamp: Date | null = null;
343	
344	    const unsubscribe = onSnapshot(reflectionDocRef, (snapshot) => {
345	      if (snapshot.exists()) {
346	        const data = snapshot.data();
347	
348	        if (initialTimestamp === null) {
349	          // First snapshot - store the initial timestamp
350	          initialTimestamp = data.updatedAt;
351	        } else {
352	          // Check if updatedAt has changed (meaning someone else saved)
353	          if (data.updatedAt.getTime() !== initialTimestamp.getTime()) {
354	            console.log("Week reflection was saved on another device - closing dialog");
355	            setPreviousWeekDialog(null);
356	          }
357	        }
358	      }
359	    }, (error) => {
360	      console.error("Error listening to reflection document:", error);
361	    });
362	
363	    return () => unsubscribe();
364	  }, [previousWeekDialog]);
365	
366	  // TEST: Keyboard shortcut to manually trigger previous week dialog (Cmd+Shift+M)
367	  useEffect(() => {
368	    const handleKeyDown = async (e: KeyboardEvent) => {
369	      // Check for Cmd+Shift+M (case insensitive)
370	      if (e.metaKey && e.shiftKey && (e.key === "M" || e.key === "m")) {
371	        e.preventDefault();
372	        console.log("Previous week dialog shortcut triggered!");
373	
374	        if (!authentication.user) {
375	          console.log("No authenticated user");
376	          return;
377	        }
378	
379	        // Get previous week
380	        const now = new Date();
381	        const { year, week } = getSequentialWeek(now);
382	        const previousWeek = week - 1;
383	        const previousYear = previousWeek < 1 ? year - 1 : year;
384	        const previousWeekNumber = previousWeek < 1 ? 52 : previousWeek;
385	
386	        try {
387	          // Query previous week's reflection
388	          const reflectionRef = collection(db, "reflections").withConverter(
389	            reflectionWeekConverter
390	          );
391	          const q = query(
392	            reflectionRef,
393	            where("userId", "==", authentication.user.uid),
394	            where("year", "==", previousYear),
395	            where("week", "==", previousWeekNumber)
396	          );
397	
398	          const querySnapshot = await getDocs(q);
399	
400	          if (!querySnapshot.empty) {
401	            const reflectionDoc = querySnapshot.docs[0].data();
402	            const reflectionDocId = querySnapshot.docs[0].id;
403	
404	            console.log('📊 Reflection document ID:', reflectionDocId);
405	            console.log('📊 Document path: reflections/' + reflectionDocId);
406	            console.log('📊 Reflection data:', reflectionDoc);
407	
408	            if (reflectionDoc.notes && reflectionDoc.notes.length > 0) {
409	              // Calculate daily counts (Mon-Fri)
410	              const dailyCounts: [number, number, number, number, number] = [
411	                0, 0, 0, 0, 0,
412	              ];
413	              reflectionDoc.completedTodos.forEach((todo) => {
414	                const todoDate = new Date(todo.date);
415	                const dayOfWeek = todoDate.getDay(); // 0=Sun, 1=Mon, ..., 5=Fri
416	                if (dayOfWeek >= 1 && dayOfWeek <= 5) {
417	                  dailyCounts[dayOfWeek - 1]++; // Convert to 0-4 index
418	                }
419	              });
420	
421	              setPreviousWeekDialog({
422	                show: true,
423	                notes: reflectionDoc.notes,
424	                week: previousWeekNumber,
425	                year: previousYear,
426	                todoCount: reflectionDoc.completedTodos.length,
427	                dailyCounts,
428	                userId: authentication.user.uid,
429	                sessionsWithoutDistractions: reflectionDoc.sessionsWithoutDistractions,
430	                totalFocusTime: reflectionDoc.totalFocusTime,
431	                averageFocusTime: reflectionDoc.averageFocusTime,
432	              });
433	            } else {
434	              console.log("No notes found for previous week");
435	            }
436	          } else {
437	            console.log("No reflection data found for previous week");
438	          }
439	        } catch (error) {
440	          console.error("Failed to fetch previous week reflection:", error);
441	        }
442	      }
443	    };
444	
445	    window.addEventListener("keydown", handleKeyDown);
446	    return () => window.removeEventListener("keydown", handleKeyDown);
447	  }, [authentication.user]);
448	
449	  // Get old uncompleted todos
450	  const oldUncompletedTodos = useMemo(
451	    () => getOldUncompletedTodos(todos),
452	    [todos]
453	  );
454	
455	  // Move old todos to next workday (or today)
456	  const moveOldTodosToNextWorkday = () => {
457	    const targetDate = getNextWorkday();
458	    const targetDateString = targetDate.toISOString().split("T")[0];
459	    const todoIds = oldUncompletedTodos.map((todo) => todo.id);
460	
461	    // Use batch operation for better performance
462	    todoOperations.moveTodosInBatch(todoIds, targetDateString);
463	
464	    // Track bulk todo move
465	    trackBulkTodoMove(oldUncompletedTodos.length);
466	  };
467	
468	  // Handle previous week dialog "Start week" - moves all uncompleted todos to today
469	  const handleStartWeek = () => {
470	    if (!previousWeekDialog) return;
471	
472	    const today = new Date();
473	    const todayString = today.toISOString().split("T")[0];
474	
475	    // Get all uncompleted todos from previous weeks/days
476	    const uncompletedTodos = todos.filter(
477	      (todo) => todo.date < todayString && !todo.completed
478	    );
479	
480	    if (uncompletedTodos.length > 0) {
481	      const todoIds = uncompletedTodos.map((todo) => todo.id);
482	      todoOperations.moveTodosInBatch(todoIds, todayString);
483	      trackBulkTodoMove(uncompletedTodos.length);
484	    }
485	
486	    // Close dialog
487	    setPreviousWeekDialog(null);
488	  };
489	
490	  // Show landing page if:
491	  // - Not running in Electron (desktop app never shows landing page) AND
492	  // - User is not authenticated AND
493	  // - User hasn't left the landing page yet (no localStorage flag)
494	  // This way, first-time users see landing page immediately,
495	  // but returning users who clicked past it won't see it during auth loading
496	  const showLandingPage =
497	    !isElectron && !authentication.user && !hasLeftLandingPage;
498	
499	  // Effect to handle pulsating animation delay
500	  useEffect(() => {
501	    if (isLoadingActivity) {
502	      const pulsateTimer = setTimeout(() => {
503	        setShouldPulsate(true);
504	      }, 1000);
505	
506	      return () => clearTimeout(pulsateTimer);
507	    } else {
508	      setShouldPulsate(false);
509	    }
510	  }, [isLoadingActivity]);
511	
512	  // Handle view changes with loading state
513	  const handleViewChange = (view: "calendar" | "activity") => {
514	    if (view === "activity" && currentView === "calendar") {
515	      // Starting to load activity
516	      setPendingView("activity");
517	      setIsLoadingActivity(true);
518	    } else if (view === "calendar") {
519	      // User clicked calendar while loading activity
520	      setPendingView(null);
521	      setIsLoadingActivity(false);
522	      setCurrentView("calendar");
523	    }
524	  };
525	
526	  // Activity loaded callback
527	  const handleActivityLoaded = () => {
528	    if (pendingView === "activity") {
529	      setCurrentView("activity");
530	      setPendingView(null);
531	    }
532	    setIsLoadingActivity(false);
533	  };
534	
535	  if (showLandingPage) {
536	    return (
537	      <LandingPage
538	        onAuthenticated={() => {
539	          localStorage.setItem("hasLeftLandingPage", "true");
540	          setHasLeftLandingPage(true);
541	        }}
542	      />
543	    );
544	  }
545	
546	  return (
547	    <div className="h-screen flex flex-col overflow-hidden">
548	      <DisconnectedNotification isDisconnected={connectionStatus === 'disconnected'} />
549	      <div className="flex-1 flex flex-col overflow-hidden">
550	        <TopBar
551	          profile={profile}
552	          onOpenSubscription={() => setShowSubscriptionDialog(true)}
553	          onOpenOnboarding={onboarding.startOnboarding}
554	          onOpenAuthModal={() => setAuthModalState(true)}
555	          currentView={currentView}
556	          onViewChange={handleViewChange}
557	          activityYear={activityYear}
558	          onActivityYearChange={setActivityYear}
559	          isLoading={authentication.isAuthenticating || isLoading}
560	          isLoadingActivity={isLoadingActivity}
561	          activeFocusTodo={focusState.todo}
562	          isFocusMinimized={focusState.isMinimized}
563	          onRestoreFocus={focusState.onRestore}
564	          shouldPulsate={shouldPulsate}
565	          connectionStatus={connectionStatus}
566	        />
567	        {authentication.user && <OnboardingNotification />}
568	        {currentView === "calendar" ? (
569	          <Calendar
570	            todos={todos}
571	            isLoading={authentication.isAuthenticating || isLoading}
572	            onAddTodo={
573	              authentication.user ? todoOperations.handleAddTodo : () => undefined
574	            }
575	            onToggleTodoComplete={
576	              authentication.user ? todoOperations.toggleTodoComplete : () => {}
577	            }
578	            onAddSession={
579	              authentication.user ? todoOperations.addTodoSession : () => {}
580	            }
581	            onMoveTodo={
582	              authentication.user ? todoOperations.moveTodo : () => {}
583	            }
584	            onCopyTodo={
585	              authentication.user ? todoOperations.copyTodo : () => {}
586	            }
587	            onResetTodoForCopy={
588	              authentication.user ? todoOperations.resetTodoForCopy : () => {}
589	            }
590	            onAddTodoWithState={
591	              authentication.user ? todoOperations.addTodoWithState : () => {}
592	            }
593	            onUpdateTodo={
594	              authentication.user ? todoOperations.updateTodo : () => {}
595	            }
596	            onDeleteTodo={
597	              authentication.user ? todoOperations.handleDeleteTodo : () => {}
598	            }
599	            onSortTodosByCompletion={
600	              authentication.user ? todoOperations.sortTodosByCompletion : () => {}
601	            }
602	            onOpenBreakDown={(todo) => setCreateMomentumDialog({ show: true, todo })}
603	            onMoveIncompleteTodosToToday={
604	              authentication.user ? moveOldTodosToNextWorkday : () => {}
605	            }
606	            hasOldUncompletedTodos={oldUncompletedTodos.length > 0}
607	            profile={profile}
608	            onFocusStateChange={(todo, isMinimized, onRestore) =>
609	              setFocusState({ todo, isMinimized, onRestore })
610	            }
611	          />
612	        ) : (
613	          <Activity
614	            year={activityYear}
615	            activityWeeks={activityWeeks}
616	            loading={activityLoading}
617	            onLoaded={handleActivityLoaded}
618	          />
619	        )}
620	        {/* Hidden Activity component to trigger loading */}
621	        {pendingView === "activity" && currentView === "calendar" && (
622	          <div style={{ display: "none" }}>
623	            <Activity
624	              year={activityYear}
625	              activityWeeks={activityWeeks}
626	              loading={activityLoading}
627	              onLoaded={handleActivityLoaded}
628	            />
629	          </div>
630	        )}
631	      </div>
632	      <AuthModal
633	        open={
634	          (!authentication.isAuthenticating && !authentication.user) ||
635	          authModalState
636	        }
637	        onSignIn={() => {
638	          setAuthModalState(false);
639	        }}
640	      />
641	      {authentication.user && (
642	        <SubscriptionDialog
643	          open={showSubscriptionDialog}
644	          onClose={() => setShowSubscriptionDialog(false)}
645	          user={authentication.user}
646	          profile={profile}
647	        />
648	      )}
649	      {previousWeekDialog?.show && (
650	        <PreviousWeekDialog
651	          notes={previousWeekDialog.notes}
652	          week={previousWeekDialog.week}
653	          year={previousWeekDialog.year}
654	          todoCount={previousWeekDialog.todoCount}
655	          dailyCounts={previousWeekDialog.dailyCounts}
656	          totalFocusTime={previousWeekDialog.totalFocusTime}
657	          averageFocusTime={previousWeekDialog.averageFocusTime}
658	          onClose={handleStartWeek}
659	        />
660	      )}
661	      {createMomentumDialog?.show && createMomentumDialog.todo && (
662	        <CreateMomentumDialog
663	          todo={createMomentumDialog.todo}
664	          isOpen={createMomentumDialog.show}
665	          onClose={() => setCreateMomentumDialog(null)}
666	          onAddTodo={todoOperations.addTodoWithState}
667	          onToggleTodoComplete={todoOperations.toggleTodoComplete}
668	        />
669	      )}
670	      {activeSurvey && (
671	        <Survey
672	          surveyId={activeSurvey.id}
673	          question={activeSurvey.questions[0]?.question || "How is your experience?"}
674	          onDismiss={dismissSurvey}
675	          onSubmit={submitSurvey}
676	        />
677	      )}
678	    </div>
679	  );
680	}
