478	/**
479	 * POST /authExchange
480	 * Exchanges session ID for one-time custom token.
481	 * Input: { sid, clientNonce }
482	 * Output: { customToken }
483	 */
484	export const authExchange = onRequest(
485	  {
486	    region: "us-central1",
487	    cors: ["*"],
488	    maxInstances: 10,
489	  },
490	  async (req, res) => {
491	    try {
492	      if (req.method !== "POST") {
493	        res.status(405).send("Method not allowed");
494	        return;
495	      }
496	
497	      const { sid, clientNonce } = req.body;
498	
499	      if (!sid || !clientNonce) {
500	        res.status(400).json({ error: "Missing sid or clientNonce" });
501	        return;
502	      }
503	
504	      // Fetch session
505	      const sessionDoc = await db
506	        .collection(SESSIONS_COLLECTION)
507	        .doc(sid)
508	        .get();
509	
510	      if (!sessionDoc.exists) {
511	        res.status(404).json({ error: "Session not found" });
512	        return;
513	      }
514	
515	      const session = sessionDoc.data() as AuthSession;
516	
517	      // Verify clientNonce matches
518	      if (session.clientNonce !== clientNonce) {
519	        res.status(403).json({ error: "Client nonce mismatch" });
520	        return;
521	      }
522	
523	      // Verify not already used
524	      if (session.used) {
525	        res.status(403).json({ error: "Token already used" });
526	        return;
527	      }
528	
529	      // Verify token exists and not expired
530	      if (!session.customToken || !session.tokenCreatedAt) {
531	        res.status(404).json({ error: "Token not ready" });
532	        return;
533	      }
534	
535	      if (Date.now() - session.tokenCreatedAt > TOKEN_TTL_MS) {
536	        await sessionDoc.ref.delete();
537	        res.status(403).json({ error: "Token expired" });
538	        return;
539	      }
540	
541	      // Mark as used and return token
542	      await sessionDoc.ref.update({ used: true });
543	
544	      res.json({ customToken: session.customToken });
545	
546	      // Clean up session after response (don't await)
547	      sessionDoc.ref.delete().catch(console.error);
548	    } catch (error) {
549	      console.error("Error in authExchange:", error);
550	      res.status(500).json({ error: "Failed to exchange token" });
551	    }
552	  }
553	);
