633	export const deleteTestUser = onCall(
634	  {
635	    region: "us-central1",
636	    cors: ["*"],
637	    maxInstances: 10,
638	  },
639	  async (req) => {
640	    try {
641	      const { uid } = req.data;
642	
643	      if (!uid) {
644	        throw new HttpsError("invalid-argument", "uid is required");
645	      }
646	
647	      // Safety check: verify it's actually a test user by checking custom claims
648	      const userRecord = await auth.getUser(uid);
649	      const customClaims = userRecord.customClaims || {};
650	
651	      if (!customClaims.isTestUser) {
652	        throw new HttpsError(
653	          "permission-denied",
654	          "Cannot delete non-test user"
655	        );
656	      }
657	
658	      // Delete user data from Firestore
