export {}

declare global {
  interface Window {
    native?: {
      getVersion: () => Promise<string>
      openExternal: (url: string) => Promise<void>
      openInWindow: (url: string, options?: { title?: string }) => Promise<void>
      onWindowClosed: (callback: () => void) => () => void
      auth: {
        startGoogleSignIn: () => Promise<string>
      }
      updater: {
        check: () => Promise<any>
        download: () => Promise<any>
        install: () => void
        onReset: (callback: () => void) => () => void
        onChecking: (callback: () => void) => () => void
        onAvailable: (callback: (info: { version: string }) => void) => () => void
        onNotAvailable: (callback: (info: { version: string }) => void) => () => void
        onError: (callback: (message: string) => void) => () => void
        onDownloadProgress: (
          callback: (progress: {
            percent: number
            bytesPerSecond: number
            total: number
            transferred: number
          }) => void
        ) => () => void
        onDownloaded: (callback: (info: { version: string }) => void) => () => void
      }
    }
  }
}

import { contextBridge, ipcRenderer } from 'electron'

// Expose a narrow, data-only API
contextBridge.exposeInMainWorld('native', {
  getVersion: () => ipcRenderer.invoke('app:getVersion'),
  openExternal: (url: string) => ipcRenderer.invoke('shell:openExternal', url),
  openInWindow: (url: string, options?: { title?: string }) => ipcRenderer.invoke('shell:openInWindow', url, options),
  onWindowClosed: (callback: () => void) => {
    const listener = () => callback()
    ipcRenderer.on('window:closed', listener)
    return () => ipcRenderer.removeListener('window:closed', listener)
  },
  auth: {
    startGoogleSignIn: () => ipcRenderer.invoke('auth:startGoogleSignIn'),
  },
  updater: {
    check: () => ipcRenderer.invoke('update:check'),
    download: () => ipcRenderer.invoke('update:download'),
    install: () => ipcRenderer.invoke('update:install'),
    onReset: (callback: () => void) => {
      const listener = () => callback()
      ipcRenderer.on('update:reset', listener)
      return () => ipcRenderer.removeListener('update:reset', listener)
    },
    onChecking: (callback: () => void) => {
      const listener = () => callback()
      ipcRenderer.on('update:checking', listener)
      return () => ipcRenderer.removeListener('update:checking', listener)
    },
    onAvailable: (callback: (info: any) => void) => {
      const listener = (_event: any, info: any) => callback(info)
      ipcRenderer.on('update:available', listener)
      return () => ipcRenderer.removeListener('update:available', listener)
    },
    onNotAvailable: (callback: (info: any) => void) => {
      const listener = (_event: any, info: any) => callback(info)
      ipcRenderer.on('update:not-available', listener)
      return () => ipcRenderer.removeListener('update:not-available', listener)
    },
    onError: (callback: (message: string) => void) => {
      const listener = (_event: any, message: string) => callback(message)
      ipcRenderer.on('update:error', listener)
      return () => ipcRenderer.removeListener('update:error', listener)
    },
    onDownloadProgress: (callback: (progress: any) => void) => {
      const listener = (_event: any, progress: any) => callback(progress)
      ipcRenderer.on('update:download-progress', listener)
      return () => ipcRenderer.removeListener('update:download-progress', listener)
    },
    onDownloaded: (callback: (info: any) => void) => {
      const listener = (_event: any, info: any) => callback(info)
      ipcRenderer.on('update:downloaded', listener)
      return () => ipcRenderer.removeListener('update:downloaded', listener)
    },
  },
  // Add more commands that the UI needs (file pickers, app paths, etc.)
})

