1	import { useCallback } from "react";
2	import { generateKeyBetween } from "fractional-indexing";
3	import { doc } from "firebase/firestore";
4	import { useAddTodo } from "./useAddTodo";
5	import { useEditTodo } from "./useEditTodo";
6	import { useBatchEditTodos } from "./useBatchEditTodos";
7	import { useDeleteTodo } from "./useDeleteTodo";
8	import { useHittingWood } from "./useHittingWood";
9	import { useOnboarding } from "../contexts/OnboardingContext";
10	import { useTodos } from "./useTodos";
11	import { usePendingTodos } from "./usePendingTodos";
12	import { sortTodosByPosition } from "../utils/todos";
13	import type { Todo } from "../App";
14	import { todosCollection, type Profile } from "../firebase";
15	import {
16	  trackTodoCreated,
17	  trackTodoCompleted,
18	  trackTodoUncompleted,
19	  trackTodoEdited,
20	  trackTodoDeleted,
21	  trackTodoMoved,
22	  trackTodoCopied,
23	  trackFreeLimitReached,
24	} from "../firebase/analytics";
25	import { extractTags } from "../utils/activity";
26	
27	interface UseTodoOperationsProps {
28	  profile: Profile | null;
29	  onShowSubscriptionDialog: () => void;
30	}
31	
32	export function useTodoOperations({ profile, onShowSubscriptionDialog }: UseTodoOperationsProps) {
33	  const { data: firebaseTodos } = useTodos();
34	  const [, addTodo] = useAddTodo();
35	  const [, editTodo] = useEditTodo();
36	  const [, batchEditTodos] = useBatchEditTodos();
37	  const [, deleteTodo] = useDeleteTodo();
38	  const hittingWood = useHittingWood();
39	  const onboarding = useOnboarding();
40	  const { addPending, removePending, updatePending, getPendingAsTodos } = usePendingTodos();
41	
42	  const handleAddTodo = useCallback(
43	    (todo: Omit<Todo, "id" | "position"> & { position?: string }): string | undefined => {
44	      const dateObj = new Date(todo.date);
45	
46	      // Check if user has reached the free limit (applies to both web and desktop)
47	      // Skip limit check during onboarding
48	      if (!onboarding.isOnboarding) {
49	        const hasActiveSubscription = profile?.subscription?.status === "active";
50	        const freeTodoCount = profile?.freeTodoCount ?? 0;
51	
52	        if (!hasActiveSubscription && freeTodoCount >= 20) {
53	          trackFreeLimitReached(freeTodoCount);
54	          onShowSubscriptionDialog();
55	          return undefined;
56	        }
57	      }
58	
59	      // Generate document ID upfront
60	      const todoDoc = doc(todosCollection);
61	      const docId = todoDoc.id;
62	
63	      // Find first position for this date (including pending todos)
64	      const allTodosForDate = [
65	        ...firebaseTodos.filter((t) => t.date.toISOString().split("T")[0] === todo.date),
66	        ...getPendingAsTodos().filter((t) => t.date === todo.date)
67	      ];
68	      const todosForDate = sortTodosByPosition(allTodosForDate);
69	
70	      const firstPosition = todosForDate.length > 0 ? todosForDate[0].position : null;
71	      const newPosition = generateKeyBetween(null, firstPosition);
72	
73	      // Add to pending immediately for optimistic update
74	      addPending({
75	        id: docId,
76	        text: todo.text,
77	        url: todo.url,
78	        completed: false,
79	        date: todo.date,
80	        position: newPosition,
81	        createdAt: new Date(),
82	        updatedAt: new Date(),
83	        isPending: true,
84	      });
85	
86	      // Add to Firebase (with the pre-generated ID and position)
87	      addTodo({ description: todo.text, date: dateObj, position: newPosition, docId });
88	
89	      // Track todo creation
90	      const hasUrl = todo.text.includes('data-url="');
91	      const hasTag = todo.text.includes('data-tag="');
92	      trackTodoCreated({
93	        hasUrl,
94	        isOnboarding: onboarding.isOnboarding,
95	      });
96	
97	      // Advance onboarding steps if applicable
98	      if (onboarding.isOnboarding) {
99	        if (hasUrl) {
100	          onboarding.notifyTodoAddedWithUrl();
101	        } else if (hasTag) {
102	          onboarding.notifyTodoAddedWithTag();
103	        } else {
104	          onboarding.notifyTodoAdded();
105	        }
106	      }
107	
108	      // Return the new todo ID so it can be selected
109	      return docId;
110	    },
111	    [onboarding, firebaseTodos, profile, addTodo, onShowSubscriptionDialog, addPending, getPendingAsTodos]
112	  );
113	
114	  const toggleTodoComplete = useCallback(
115	    (todoId: string) => {
116	      const todo = firebaseTodos.find((t) => t.id === todoId);
117	      if (!todo) return;
118	
119	      const isCompleting = !todo.completed;
120	
121	      // Play sound when completing a todo
122	      if (isCompleting) {
123	        hittingWood.play();
124	      }
125	
126	      // Update Firestore - scheduled function will read these later
127	      editTodo({
128	        id: todoId,
129	        description: todo.description,
130	        completed: isCompleting,
131	        date: todo.date,
132	        completedAt: isCompleting ? new Date() : undefined,
133	      });
134	
135	      // Track analytics
136	      if (isCompleting) {
137	        trackTodoCompleted({ isOnboarding: onboarding.isOnboarding });
138	      } else {
139	        trackTodoUncompleted({ isOnboarding: onboarding.isOnboarding });
140	      }
141	    },
142	    [firebaseTodos, hittingWood, editTodo, onboarding.isOnboarding]
143	  );
144	
145	  const addTodoSession = useCallback(
146	    (todoId: string, minutes: number, deepFocus: boolean) => {
147	      const todo = firebaseTodos.find((t) => t.id === todoId);
148	      if (!todo) return;
149	
150	      // Get existing sessions or initialize empty array
151	      const existingSessions = todo.sessions || [];
152	
153	      // Add new session
154	      const newSessions = [
155	        ...existingSessions,
156	        { minutes, deepFocus, createdAt: new Date() },
157	      ];
158	
159	      // Update Firestore with sessions array
160	      editTodo({
161	        id: todoId,
162	        description: todo.description,
163	        completed: todo.completed,
164	        date: todo.date,
165	        sessions: newSessions,
166	      });
167	
168	      // TODO: Track analytics with trackFocusSessionAdded
169	    },
170	    [firebaseTodos, editTodo]
171	  );
172	
173	  const moveTodo = useCallback(
174	    (todoId: string, newDate: string, newIndex?: number) => {
175	      const todo = firebaseTodos.find((t) => t.id === todoId);
176	      if (!todo) return;
177	
178	      // Get todos for target date, sorted by position (excluding the dragged todo)
179	      const todosInTargetDate = sortTodosByPosition(
180	        firebaseTodos.filter((t) => t.date.toISOString().split("T")[0] === newDate && t.id !== todoId)
181	      );
182	
183	      let newPosition: string;
184	
185	      if (newIndex === undefined || todosInTargetDate.length === 0) {
186	        // Moving to a date without specific position - place at end
187	        const lastTodo = todosInTargetDate[todosInTargetDate.length - 1];
188	        newPosition = generateKeyBetween(lastTodo?.position || null, null);
189	      } else {
190	        // Moving to specific position
191	        const beforeTodo = todosInTargetDate[newIndex - 1];
192	        const afterTodo = todosInTargetDate[newIndex];
193	        newPosition = generateKeyBetween(beforeTodo?.position || null, afterTodo?.position || null);
194	      }
195	
196	      // Convert string date to Date object
197	      const dateObj = new Date(newDate);
198	
199	      // Increment moveCount only when actually changing dates
200	      const isChangingDate = todo.date.toISOString().split("T")[0] !== newDate;
201	      const newMoveCount = isChangingDate ? (todo.moveCount || 0) + 1 : (todo.moveCount || 0);
202	
203	      editTodo({
204	        id: todoId,
205	        description: todo.description,
206	        completed: todo.completed,
207	        date: dateObj,
208	        position: newPosition,
209	        moveCount: newMoveCount,
